public int minWastedSpace(int[] nums, int k) {
    int n = nums.length;
    int[][] dp = new int[n + 1][k + 1];
    for(int[] row : dp) Arrays.fill(row, Integer.MAX_VALUE);
    dp[0][0] = 0;

    for(int i = 1; i <= n; ++i) {
        int total = 0;
        for(int j = i; j > 0; --j) {
            total += nums[j - 1];
            for(int l = 0; l < k; ++l) {
                dp[i][l + 1] = Math.min(dp[i][l + 1], dp[j - 1][l] + (i - j + 1) * nums[j - 1] - total);
            }
        }
    }

    int min = dp[n][0];
    for(int s : dp[n]) min = Math.min(min, s);
    return min;
}
